# ============================================================
# Dataset for PyTorch
# ============================================================

if ML_AVAILABLE:
    class LabeledImageDataset(Dataset):
        def __init__(self, image_ids, labels, class_to_idx, transform=None):
            self.image_ids = image_ids
            self.labels = labels
            self.class_to_idx = class_to_idx
            self.transform = transform or transforms.Compose([
                transforms.Resize((224, 224)),
                transforms.ToTensor(),
                transforms.Normalize(mean=[0.485, 0.456, 0.406],
                                     std=[0.229, 0.224, 0.225])
            ])

        def __len__(self):
            return len(self.image_ids)

        def __getitem__(self, idx):
            image_id = self.image_ids[idx]
            image_data = image_store[image_id]["data"]
            image = Image.open(BytesIO(image_data)).convert("RGB")
            if self.transform:
                image = self.transform(image)
            label_idx = self.class_to_idx[self.labels[idx]]
            return image, label_idx

# ============================================================
# Helper Functions
# ============================================================

def majority_vote(annotations: dict) -> tuple:
    """Compute majority vote from annotations."""
    if not annotations:
        return None, {}, 0, 0.0
    labels = list(annotations.values())
    counter = Counter(labels)
    total = len(labels)
    most_common_label, most_common_count = counter.most_common(1)[0]
    agreement_ratio = most_common_count / total
    return most_common_label, dict(counter), total, agreement_ratio

def aggregate_all_labels():
    """Re-aggregate labels for all images."""
    aggregated_labels.clear()
    for image_id, annotations in annotations_store.items():
        if annotations:
            label, _, _, _ = majority_vote(annotations)
            if label is not None:
                aggregated_labels[image_id] = label

