@app.post("/images/upload")
def upload_image(file: UploadFile = File(...), image_id: Optional[str] = Form(None)):
    """Upload an image for labeling."""
    img_id = image_id or str(uuid.uuid4())[:12]
    if img_id in image_store:
        raise HTTPException(status_code=400, detail=f"Image '{img_id}' already exists.")
    
    data = file.file.read()
    
    # Validate it's a valid image if PIL is available
    if ML_AVAILABLE:
        try:
            Image.open(BytesIO(data))
        except Exception:
            raise HTTPException(status_code=400, detail="Invalid image file.")
    
    image_store[img_id] = {
        "filename": file.filename,
        "data": data
    }
    annotations_store[img_id] = {}
    
    return {"image_id": img_id, "filename": file.filename, "message": "Image uploaded successfully."}

