@app.post("/annotations", response_model=AnnotationResponse)
def submit_annotation(annotation: AnnotationCreate):
    """Submit a label annotation for an image."""
    if annotation.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found.")
    if annotation.annotator_id not in annotators_store:
        raise HTTPException(status_code=404, detail="Annotator not found. Please register first.")
    
    image_id = annotation.image_id
    annotator_id = annotation.annotator_id
    label = annotation.label.strip()
    
    if not label:
        raise HTTPException(status_code=400, detail="Label cannot be empty.")
    
    # Check if annotator already labeled this image
    already_labeled = annotator_id in annotations_store.get(image_id, {})
    
    # Store annotation
    if image_id not in annotations_store:
        annotations_store[image_id] = {}
    annotations_store[image_id][annotator_id] = label
    
    # Update annotator stats
    if not already_labeled:
        annotators_store[annotator_id]["total_annotations"] += 1
    
    # Track label classes
    label_classes.add(label)
    
    # Re-aggregate for this image
    agg_label, _, _, _ = majority_vote(annotations_store[image_id])
    if agg_label:
        aggregated_labels[image_id] = agg_label
    
    msg = "Annotation updated." if already_labeled else "Annotation submitted."
    return AnnotationResponse(
        image_id=image_id,
        annotator_id=annotator_id,
        label=label,
        message=msg
    )

@app.post("/annotations/bulk")
def submit_bulk_annotations(annotations: list[AnnotationCreate]):
    """Submit multiple annotations at once."""
    results = []
    errors = []
    for i, ann in enumerate(annotations):
        try:
            result = submit_annotation(ann)
            results.append({"index": i, "status": "success", "data": result.dict()})
        except HTTPException as e:
            errors.append({"index": i, "status": "error", "detail": e.detail})
    return {"submitted": len(results), "errors": len(errors), "results": results, "error_details": errors}

@app.get("/annotations/{image_id}")
def get_annotations(image_id: str):
    """Get all annotations for an image."""
    if image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found.")
    anns = annotations_store.get(image_id, {})
    return {"image_id": image_id, "annotations": anns, "count": len(anns)}

@app.delete("/annotations/{image_id}/{annotator_id}")
def delete_annotation(image_id: str, annotator_id: str):
    """Delete a specific annotation."""
    if image_id not in annotations_store or annotator_id not in annotations_store.get(image_id, {}):
        raise HTTPException(status_code=404, detail="Annotation not found.")
    del annotations_store[image_id][annotator_id]
    annotators_store[annotator_id]["total_annotations"] = max(
        0, annotators_store[annotator_id]["total_annotations"] - 1
    )
    # Re-aggregate
    if annotations_store[image_id]:
        agg_label, _, _, _ = majority_vote(annotations_store[image_id])
        aggregated_labels[image_id] = agg_label
    else:
        aggregated_labels.pop(image_id, None)
    return {"message": "Annotation deleted."}

