@app.get("/aggregate/{image_id}", response_model=AggregationResult)
def aggregate_image_labels(image_id: str):
    """Aggregate labels for a specific image using majority voting."""
    if image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found.")
    anns = annotations_store.get(image_id, {})
    if not anns:
        raise HTTPException(status_code=400, detail="No annotations for this image.")
    
    label, vote_counts, total, agreement = majority_vote(anns)
    aggregated_labels[image_id] = label
    
    return AggregationResult(
        image_id=image_id,
        aggregated_label=label,
        vote_counts=vote_counts,
        total_votes=total,
        agreement_ratio=round(agreement, 4)
    )

