@app.get("/stats")
def get_statistics():
    """Get overall system statistics."""
    aggregate_all_labels()
    
    total_annotations = sum(len(anns) for anns in annotations_store.values())
    images_with_annotations = sum(1 for anns in annotations_store.values() if anns)
    
    # Agreement statistics
    agreements = []
    for anns in annotations_store.values():
        if len(anns) >= 2:
            _, _, _, agreement = majority_vote(anns)
            agreements.append(agreement)
    
    avg_agreement = round(np.mean(agreements), 4) if agreements else None
    
    # Label distribution
    all_labels = []
    for anns in annotations_store.values():
        all_labels.extend(anns.values())
    label_distribution = dict(Counter(all_labels))
    
    # Aggregated label distribution
    agg_distribution = dict(Counter(aggregated_labels.values()))
    
    return {
        "total_images": len(image_store),
        "total_annotators": len(annotators_store),
        "total_annotations": total_annotations,
        "images_with_annotations": images_with_annotations,
        "images_with_aggregated_labels": len(aggregated_labels),
        "unique_labels": sorted(list(label_classes)),
        "average_agreement": avg_agreement,
        "label_distribution": label_distribution,
        "aggregated_label_distribution": agg_distribution,
        "model_trained": model_state["trained"]
    }

@app.get("/stats/annotators")
def get_annotator_statistics():
    """Get per-annotator statistics including agreement with majority."""
    aggregate_all_labels()
    
    annotator_stats = []
    for aid, info in annotators_store.items():
        agreements = 0
        disagreements = 0
        for img_id, anns in annotations_store.items():
            if aid in anns and img_id in aggregated_labels:
                if anns[aid] == aggregated_labels[img_id]:
                    agreements += 1
                else:
                    disagreements += 1
        total = agreements + disagreements
        accuracy = round(agreements / total, 4) if total > 0 else None
        annotator_stats.append({
            "annotator_id": aid,
            "name": info["name"],
            "total_annotations": info["total_annotations"],
            "agreements_with_majority": agreements,
            "disagreements_with_majority": disagreements,
            "accuracy_vs_majority": accuracy
        })
    
    return {"annotator_statistics": annotator_stats}

