    """Predict label for an uploaded image (not stored)."""
    if not ML_AVAILABLE:
        raise HTTPException(status_code=500, detail="ML libraries not available.")
    if not model_state["trained"]:
        raise HTTPException(status_code=400, detail="Model not trained yet.")
    
    model = model_state["model"]
    classes = model_state["classes"]
    device = model_state["device"]
    
    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    
    data = file.file.read()
    try:
        image = Image.open(BytesIO(data)).convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image file.")
    
    image_tensor = transform(image).unsqueeze(0).to(device)
    
    model.eval()
    with torch.no_grad():
        outputs = model(image_tensor)
        probabilities = torch.softmax(outputs, dim=1)[0]
        confidence, predicted_idx = torch.max(probabilities, 0)
    
    predicted_label = classes[predicted_idx.item()]
    all_probs = {classes[i]: round(probabilities[i].item(), 4) for i in range(len(classes))}
    
    return {
        "filename": file.filename,
        "predicted_label": predicted_label,
        "confidence": round(confidence.item(), 4),
        "all_probabilities": all_probs
    }

